def guesses_to_score(guesses):
    delta = 5

    if guesses < 1e3 + delta:
        return 0
    elif guesses < 1e6 + delta:
        return 1
    elif guesses < 1e8 + delta:
        return 2
    elif guesses < 1e10 + delta:
        return 3
    else:
        return 4

